{
  "domain_analysis": {
    "business_context": "A multi-jurisdiction logistics platform adding real-time driver earnings transparency. The feature intersects three distinct legal regimes with fundamentally different driver classifications (employee vs. independent contractor), different regulatory requirements (mandatory vs. optional transparency), and different organizational approval gates (works council co-determination). This is not one feature — it is three jurisdiction-specific implementations sharing a UI concept.",
    "bounded_context": "Driver Compensation / Earnings Visibility",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The guaranteed compensation component before bonuses, tips, or deductions. For CA employees, this must meet or exceed minimum wage independently of tips. For ID contractors, this is the per-task platform rate." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation tied to completing a delivery. May include surge pricing, distance bonuses, or volume incentives. Calculation rules vary by jurisdiction." },
      { "term": "Tip", "definition": "Gratuity paid by the customer intended for the driver. In California, tips are the sole property of the employee and MUST NOT be credited toward minimum wage obligations (CA Labor Code §351)." },
      { "term": "Deduction", "definition": "AMBIGUOUS TERM — see escalation. For CA employees: legally enumerated withholdings (tax, benefits, court-ordered garnishments) per Labor Code §221-224. For ID contractors: platform commission, service fees, or equipment charges. These are fundamentally different financial instruments sharing one label." },
      { "term": "Itemized Wage Statement", "definition": "In California, a legally mandated document per pay period showing gross wages, total hours, deductions, net wages, pay period dates, and employer info (Labor Code §226). The real-time display likely creates a de facto wage statement with legal obligations." },
      { "term": "Works Council (Betriebsrat)", "definition": "German employee representative body with statutory co-determination rights. Must formally approve changes to systems that monitor or display employee compensation before deployment (BetrVG §87)." },
      { "term": "Driver Classification", "definition": "The legal relationship between driver and platform — employee (CA under AB5) or independent contractor (ID). Determines which labor laws apply, what must be displayed, and what deductions are permissible." },
      { "term": "Earnings Breakdown", "definition": "The decomposition of total earnings into constituent components. The required granularity and mandatory components differ by jurisdiction." },
      { "term": "Real-Time Display", "definition": "Showing earnings as they accrue during a work session. Distinct from a final pay-period statement. Creates reconciliation risk if preliminary figures diverge from final payroll." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "In California, the earnings breakdown MUST include at minimum: gross wages earned, total hours worked, all deductions with itemized descriptions, net wages, and the inclusive dates of the pay period — per Labor Code §226.",
      "invariant": true,
      "invariant_justification": "Failure to provide compliant itemized wage statements exposes the platform to penalties of $50-$100 per violation per employee per pay period, plus attorney fees. This is a statutory requirement, not a policy choice.",
      "testable_assertion": "Given a California driver, when viewing their earnings breakdown, then ALL of the following are displayed: gross wages, hours worked, itemized deductions, net wages, and pay period dates."
    },
    {
      "id": "BR-2",
      "rule": "In California, tips MUST be displayed as a line item fully separate from base pay and MUST NOT be factored into minimum wage calculations.",
      "invariant": true,
      "invariant_justification": "CA Labor Code §351 prohibits employers from crediting tips against minimum wage. Displaying them in a way that conflates tips with base compensation could constitute evidence of a wage violation.",
      "testable_assertion": "Given a California driver with $50 base pay and $20 tips, when viewing the breakdown, then base pay shows $50 and tips show $20 as distinct line items, and any minimum wage compliance indicator uses only the $50 base pay figure."
    },
    {
      "id": "BR-3",
      "rule": "The Germany rollout MUST NOT proceed until the applicable Betriebsrat has formally approved the compensation display system design.",
      "invariant": true,
      "invariant_justification": "BetrVG §87(1)(6) grants works councils co-determination rights over technical systems that monitor employee performance or behavior. Compensation display systems fall under this. Deploying without approval is a legal violation that can result in injunctions and the system being shut down entirely.",
      "testable_assertion": "Given the Germany locale, when the Betriebsrat approval flag is not set to 'approved', then the earnings transparency feature MUST NOT be accessible to any German driver."
    },
    {
      "id": "BR-4",
      "rule": "Deductions shown to California employees MUST only include legally permissible deductions (taxes, court-ordered withholdings, employee-authorized benefit deductions). No platform fees or commissions may appear as 'deductions' for employees.",
      "invariant": true,
      "invariant_justification": "CA Labor Code §221-224 strictly limits what an employer may deduct from employee wages. Displaying impermissible deductions implies they are being taken, creating legal exposure even if the amounts are correct.",
      "testable_assertion": "Given a California driver (employee), when viewing deductions, then only tax withholdings, court-ordered garnishments, and explicitly authorized benefit deductions appear. Platform fees or commissions MUST NOT be listed."
    },
    {
      "id": "BR-5",
      "rule": "For Indonesian independent contractors, platform commission and service fees are displayed as separate line items from earnings, clearly labeled as contractor platform fees — NOT as 'deductions'.",
      "invariant": false,
      "invariant_justification": "While not legally mandated in Indonesia, mislabeling platform fees as 'deductions' risks reclassification arguments if Indonesian labor law evolves. This is a protective business policy.",
      "testable_assertion": "Given an Indonesian driver (contractor), when viewing their earnings, then platform fees appear with labels like 'Platform Service Fee' or 'Commission', never as 'Deduction'."
    },
    {
      "id": "BR-6",
      "rule": "Real-time earnings displays MUST include a visible disclaimer that figures are preliminary and subject to final reconciliation at the end of the pay period.",
      "invariant": false,
      "invariant_justification": "A business policy to mitigate disputes when real-time figures differ from final payroll. Especially important in California where discrepancies on wage statements carry statutory penalties.",
      "testable_assertion": "Given any driver viewing real-time earnings, when the current pay period has not yet closed, then a disclaimer indicating figures are preliminary is visible on screen."
    },
    {
      "id": "BR-7",
      "rule": "Earnings data MUST be scoped to the authenticated driver. A driver must never see another driver's earnings, even partially.",
      "invariant": true,
      "invariant_justification": "Leaking compensation data between drivers violates privacy regulations in all three jurisdictions (CCPA, GDPR, Indonesian PDP Law) and creates operational risk.",
      "testable_assertion": "Given driver A is authenticated, when requesting earnings data, then only driver A's records are returned. Any request for driver B's data returns an authorization error."
    },
    {
      "id": "BR-8",
      "rule": "The earnings breakdown components and display rules MUST be jurisdiction-aware: the system must resolve which rules apply based on the driver's operating jurisdiction, not the driver's nationality or the platform's HQ location.",
      "invariant": true,
      "invariant_justification": "Labor law applies based on where work is performed. A German national driving in California is subject to California rules. Applying the wrong jurisdiction's rules creates compliance violations.",
      "testable_assertion": "Given a driver whose operating jurisdiction is California, when displaying earnings, then California-specific display rules (itemized wage statement format, tip separation, permissible deductions) are applied regardless of driver's country of origin."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver classified as an employee in California",
      "when": "They open the earnings breakdown screen",
      "then": "They see gross wages, hours worked, itemized deductions (each labeled), tips as a separate line, net wages, and pay period dates — all per Labor Code §226"
    },
    {
      "id": "AC-2",
      "given": "A driver in Germany where Betriebsrat approval has NOT been granted",
      "when": "They attempt to access the earnings transparency feature",
      "then": "The feature is unavailable and they see a message indicating it is not yet active in their region"
    },
    {
      "id": "AC-3",
      "given": "A driver in Germany where Betriebsrat approval HAS been granted",
      "when": "They open the earnings breakdown screen",
      "then": "They see their earnings breakdown in compliance with whatever format the Betriebsrat approved"
    },
    {
      "id": "AC-4",
      "given": "An independent contractor driver in Indonesia",
      "when": "They view their earnings",
      "then": "They see base pay, per-delivery bonuses, tips, and platform fees — with platform fees clearly labeled as fees/commissions, not deductions"
    },
    {
      "id": "AC-5",
      "given": "A California employee driver during an active shift (pay period not closed)",
      "when": "They view real-time earnings",
      "then": "A visible disclaimer states that displayed figures are preliminary and subject to final payroll reconciliation"
    },
    {
      "id": "AC-6",
      "given": "Any authenticated driver",
      "when": "The system renders earnings data",
      "then": "Only that driver's own earnings data is included; no other driver's data is accessible or leaked"
    },
    {
      "id": "AC-7",
      "given": "A California employee driver who received $15 in tips",
      "when": "Viewing the earnings breakdown",
      "then": "Tips appear as their own line item, visually and logically separated from base pay, and are not included in any hourly rate or minimum wage calculation displayed"
    },
    {
      "id": "AC-8",
      "given": "A driver whose operating jurisdiction is California but whose profile nationality is Indonesian",
      "when": "Viewing their earnings breakdown",
      "then": "California employee rules apply, not Indonesian contractor rules"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Driver crosses jurisdiction boundaries during a single shift (e.g., starts in one German state with Betriebsrat approval, delivers in another without)",
      "expected_behavior": "Earnings display rules should follow the most restrictive applicable jurisdiction. If any portion of work occurs in an unapproved jurisdiction, that portion must be handled according to that jurisdiction's requirements."
    },
    {
      "scenario": "Real-time earnings show a preliminary figure that differs from final payroll due to tip adjustments, retroactive bonuses, or correction of hours",
      "expected_behavior": "The final pay-period statement takes precedence. The system must maintain an audit trail showing the preliminary vs. final figures. In California, the final itemized wage statement must be accurate — real-time was informational only."
    },
    {
      "scenario": "A California driver's real-time earnings display reveals they are currently below minimum wage for hours worked",
      "expected_behavior": "This is a significant edge case. The system should NOT suppress the data (transparency is the point), but the platform must have a process to ensure minimum wage compliance by end of pay period. Displaying sub-minimum-wage real-time figures is legally risky — consult employment counsel."
    },
    {
      "scenario": "Betriebsrat approval is revoked or expires in Germany after the feature has been live",
      "expected_behavior": "The feature must be immediately deactivated for all German drivers. The system needs a kill switch that can disable the feature per jurisdiction without redeployment."
    },
    {
      "scenario": "Driver has zero earnings for a pay period (e.g., no deliveries completed)",
      "expected_behavior": "Display a valid breakdown showing $0 across all components. For California employees, an itemized wage statement is still required if they were scheduled or on-call."
    },
    {
      "scenario": "Indonesian regulatory environment changes and reclassifies drivers as employees",
      "expected_behavior": "The jurisdiction-aware rule engine must be updatable without code changes. Indonesia would switch from contractor display rules to employee display rules, including adding mandatory itemized deductions."
    },
    {
      "scenario": "A tip is disputed or reversed after being displayed in real-time",
      "expected_behavior": "The real-time display updates to reflect the reversal. An audit entry is created. For California, the reversal must appear as a clearly labeled adjustment on the next itemized statement — not silently removed."
    }
  ],

  "business_impact": {
    "financial": "Non-compliance with CA Labor Code §226 carries penalties of $50 per employee per initial violation and $100 per subsequent violation per pay period, plus attorney fees in class actions. German Betriebsrat violations can result in injunctions halting the feature entirely. Correct implementation builds driver trust and may reduce turnover — a major cost driver in logistics (estimated $3,000-$5,000 per driver replacement).",
    "operational": "Requires a jurisdiction-aware rules engine, not a single global implementation. Three distinct compliance paths must be maintained. The Germany rollout has an external dependency (Betriebsrat approval) that is NOT under engineering control and may take weeks to months. Operational teams need a per-jurisdiction feature gate and a kill switch.",
    "user": "Drivers gain visibility into how their pay is calculated, building trust. In California, this fulfills a legal right. In Indonesia, this is a competitive differentiator for driver recruitment. Poor implementation (confusing labels, inconsistent data) erodes the trust it's meant to build.",
    "risk": "HIGH in California (wage statement litigation is a mature plaintiff's bar specialty — class action exposure). MEDIUM in Germany (Betriebsrat non-compliance can halt operations). LOW in Indonesia (no legal mandate, but misclassification risk if terminology implies employment). Cross-jurisdictional data display creates GDPR risk if German driver data is processed outside compliant infrastructure.",
    "stakeholders_affected": [
      { "group": "Drivers (California)", "impact": "Gain legally required wage transparency; incorrect implementation directly harms them and exposes platform to class action" },
      { "group": "Drivers (Germany)", "impact": "Feature blocked until Betriebsrat approval; must be clearly communicated to avoid frustration if other regions launch first" },
      { "group": "Drivers (Indonesia)", "impact": "Gain optional transparency as a trust-building measure; contractor-appropriate terminology is essential to avoid reclassification risk" },
      { "group": "Legal/Compliance Team", "impact": "Must review all display formats per jurisdiction before launch; California wage statement format needs legal sign-off" },
      { "group": "German Works Council (Betriebsrat)", "impact": "Must be engaged early as a co-decision-maker, not informed after the fact; has power to block or modify the feature" },
      { "group": "Payroll/Finance", "impact": "Real-time display must reconcile with payroll systems; discrepancies create disputes and legal exposure" },
      { "group": "Product/Engineering", "impact": "Must build a jurisdiction-aware rules engine, not a one-size-fits-all screen; significantly higher complexity than a single global feature" },
      { "group": "Platform (Business)", "impact": "Competitive advantage in driver recruitment and retention; legal compliance reduces litigation risk; phased rollout required due to Germany blocker" }
    ]
  },

  "confidence": {
    "level": 45,
    "reasoning": "The spec uses the term 'deductions' uniformly across three jurisdictions where it has fundamentally different legal meanings — this is a domain-level contradiction that could lead to incorrect implementation. Additionally, 'real-time' display of wage data for California employees creates unaddressed legal risk around preliminary vs. final wage statements. The Germany rollout has an unresolved external dependency (Betriebsrat timeline). Without legal counsel review of the specific display formats per jurisdiction, confidence cannot exceed 50.",
    "high_confidence_areas": [
      "California requires itemized wage statements — this is settled law",
      "Germany requires Betriebsrat approval before rollout — this is settled law",
      "Tips must be separated from base pay in California — this is settled law",
      "Driver data must be scoped to the authenticated driver — universal privacy requirement",
      "Jurisdiction of work (not nationality) determines applicable rules"
    ],
    "low_confidence_areas": [
      "Exact legal risk of showing real-time preliminary figures that may differ from final CA wage statements",
      "Whether real-time display constitutes a de facto wage statement triggering §226 requirements on every screen view",
      "Specific format requirements the Betriebsrat will demand in Germany — unknown until negotiation",
      "Whether Indonesian regulatory environment is stable enough to rely on current contractor classification",
      "GDPR implications of processing German driver compensation data in a global real-time system"
    ],
    "assumptions": [
      "The platform's existing payroll system is the source of truth for final earnings, and real-time display is informational",
      "Driver classification (employee vs. contractor) is already correctly determined per jurisdiction and is not in scope for this feature",
      "The platform has or will build jurisdiction-aware feature gating capability",
      "Legal counsel will review the specific display format for each jurisdiction before launch"
    ]
  },

  "escalations": [
    {
      "type": "contradiction",
      "description": "The spec uses 'deductions' as a uniform earnings component across all three jurisdictions, but 'deductions' has fundamentally different legal meanings: in California, it refers to legally enumerated withholdings from employee wages (taxes, garnishments); in Indonesia, the equivalent concept is platform fees/commissions charged to contractors. These are not the same financial instrument and MUST NOT share a label or data model. Treating them identically will either (a) show illegal deduction types to CA employees or (b) mischaracterize contractor fees as wage deductions, creating reclassification risk in Indonesia.",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Legal/Compliance", "Payroll/Finance"],
      "options": [
        "A: Define jurisdiction-specific earnings component taxonomies — 'Deductions' for CA employees (legally enumerated), 'Platform Fees' for ID contractors, and defer Germany terminology to Betriebsrat negotiation",
        "B: Use a generic 'Adjustments' category everywhere and let each jurisdiction define its sub-items",
        "C: Remove 'deductions' from the spec entirely and replace with jurisdiction-specific component definitions"
      ],
      "recommendation": "Option A. Each jurisdiction needs its own vocabulary for what reduces gross pay. Forcing a single term across employee and contractor contexts is a domain error that will propagate into the UI, data model, and payroll integration."
    },
    {
      "type": "ambiguity",
      "description": "'Real-time' is undefined. Does it mean per-delivery update, per-minute polling, or live streaming? For California employees, there is a meaningful legal distinction between an informational live dashboard and a formal itemized wage statement. If the real-time display is treated as a wage statement, every refresh must comply with §226. If it's informational, it needs a prominent disclaimer. The spec does not clarify this boundary.",
      "affected_stakeholders": ["Drivers (California)", "Legal/Compliance", "Engineering"],
      "options": [
        "A: Define real-time display as an informational dashboard with a mandatory 'preliminary' disclaimer, with the formal wage statement generated only at pay period close",
        "B: Define real-time display as a continuously updated wage statement that must comply with §226 at all times",
        "C: Defer to legal counsel to determine the classification"
      ],
      "recommendation": "Option A with mandatory legal review. Option B is operationally impractical (tip adjustments, retroactive changes make continuous compliance impossible). But legal counsel must confirm that a disclaimer is sufficient to distinguish the dashboard from a formal wage statement."
    },
    {
      "type": "missing_context",
      "description": "The spec does not address the Betriebsrat negotiation timeline or process for Germany. This is not a technical dependency — it is an organizational and legal dependency that determines when (or if) the feature can launch in Germany. Engineering cannot unblock this. The spec needs to define: (1) Who owns the Betriebsrat relationship? (2) What is the expected timeline? (3) What is the rollout strategy if Germany approval is delayed months beyond other regions?",
      "affected_stakeholders": ["Drivers (Germany)", "German Works Council", "Product/Engineering", "Legal"],
      "options": [
        "A: Launch CA and ID first, Germany when approved — requires feature gating by jurisdiction",
        "B: Hold all jurisdictions until Germany is approved — delays value delivery",
        "C: Launch a minimal version in Germany that Betriebsrat pre-approves, full version later"
      ],
      "recommendation": "Option A. California has a legal obligation to provide transparency now. Blocking it on a German organizational process is unjustifiable. Build jurisdiction-level feature gates from day one."
    }
  ],

  "rejection_reasons": [
    {
      "violation": "Using a single 'deductions' concept across employee and contractor jurisdictions",
      "business_rule_broken": "BR-4, BR-5 — California employee deductions and Indonesian contractor platform fees are legally and semantically distinct. A unified 'deductions' model will either show illegal deduction types to employees or mislabel contractor fees."
    },
    {
      "violation": "Launching in Germany without explicit Betriebsrat approval gate",
      "business_rule_broken": "BR-3 — BetrVG §87 co-determination rights are non-negotiable. Any architecture that does not include a hard gate for Germany approval is non-compliant."
    },
    {
      "violation": "Treating the feature as a single global implementation with cosmetic locale differences",
      "business_rule_broken": "BR-8 — Jurisdiction determines the entire rule set (components shown, labels used, legal disclaimers, approval gates). This is three features sharing a concept, not one feature with translations."
    }
  ]
}

